searchTracks:
async (query, limit = 15) => {
  try {
    const encoded = encodeURIComponent(query);
    const url = `${this.BASE_URL}/catalog/search?query=${encoded}&type=tracks&limit=${limit}`;
    const data = await this.fetchWithTimeout(url);

    if (!data.tracks?.items?.length) return { tracks: [], total: 0 };

    const filtered = data.tracks.items
      .filter(item => this.isHiRes(item))
      .map(item => ({
        id: item.id.toString(),
        title: item.title,
        artist: item.performer?.name || 'Unknown',
        album: item.album?.title || '',
        duration: item.duration,
        albumCover: item.album?.image?.large || '',
        audioQuality: 'HI_RES'
      }));

    return { tracks: filtered.slice(0, limit), total: filtered.length };
  } catch (e) {
    console.error('[Qobuz Bitch] Search error:', e.message);
    return { tracks: [], total: 0 };
  }
}
